const input = $('When Executed by Another Workflow').item.json;

function parseDate(raw) {
  if (!raw) return null;
  raw = String(raw).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;
  const parsed = new Date(raw);
  if (!isNaN(parsed)) return parsed.toISOString().split('T')[0];
  const hoy = new Date();
  const r = raw.toLowerCase();
  if (r === 'hoy')    return hoy.toISOString().split('T')[0];
  if (r === 'mañana') { hoy.setDate(hoy.getDate() + 1); return hoy.toISOString().split('T')[0]; }
  return null;
}

const fecha = parseDate(input.fecha_recepcion || input['fecha_recepcion'] || input.fecha);
if (!fecha) {
  throw new Error(`Fecha inválida recibida: "${input.fecha_recepcion}". Se requiere formato YYYY-MM-DD.`);
}

function parseHora(raw) {
  if (!raw) return null;
  raw = String(raw).trim();
  if (/^\d{2}:\d{2}$/.test(raw)) return raw;
  if (/^\d{1,2}:\d{2}$/.test(raw)) return raw.padStart(5, '0');
  if (raw === '9:00' || raw === '9') return '09:00';
  if (raw === '15:00' || raw === '15') return '15:00';
  return raw;
}

const sinAcentos = (s) => String(s || '')
  .toLowerCase()
  .normalize('NFD').replace(/[̀-ͯ]/g, '')
  .trim();

function normalizeVehiculo(raw) {
  const v = sinAcentos(raw);
  if (!v) return '';
  if (v.includes('moto')) return 'Moto';
  if (v.includes('camioneta') || v.includes('pickup') || v.includes('pick up')) return 'Camioneta';
  if (v.includes('suv')) return 'SUV';
  if (v.includes('auto') || v.includes('sedan') || v.includes('automovil') || v.includes('vehiculo')) return 'Auto';
  return String(raw).trim();
}

function normalizeServicio(raw) {
  const s = sinAcentos(raw);
  if (!s) return '';
  if (s.includes('completo') && s.includes('interior')) return 'Lavado completo exterior e interior';
  if (s.includes('completo') && s.includes('exterior')) return 'Lavado completo exterior';
  if (s.includes('basico') && s.includes('exterior'))   return 'Lavado básico exterior';
  if (s.includes('descontaminad'))                      return 'Lavado + descontaminado full';
  if (s.includes('abrillantado') && s.includes('pintura')) return 'Abrillantado de pintura';
  if (s.includes('abrillantado') && (s.includes('cromad') || s.includes('cromo'))) return 'Abrillantado de cromados';
  if (s.includes('limpieza') && s.includes('interior')) return 'Limpieza interior';
  if (s.includes('interior'))                           return 'Limpieza interior';
  if (s.includes('basico'))                             return 'Lavado básico';
  return String(raw).trim();
}

const vehiculo = normalizeVehiculo(input.vehiculo);
const servicio = normalizeServicio(input.servicio);

return [{
  json: {
    nombre:    String(input.nombre  || '').trim(),
    telefono:  String(input.telefono|| '').trim(),
    vehiculo,
    servicio,
    fecha_recepcion: fecha,
    hora:      parseHora(input.hora) || String(input.hora || '').trim()
  }
}];

const n = $('Normalizar datos entrada').first().json;
const servicios = $input.all().map(i => i.json);

const norm = (s) => String(s || '')
  .toLowerCase()
  .normalize('NFD').replace(/[̀-ͯ]/g, '')
  .trim();

// Notion (simple:true) devuelve las claves como property_tipo / property_nombre / property_precio
const match = servicios.find(s =>
  norm(s.property_tipo) === norm(n.vehiculo) && norm(s.property_nombre) === norm(n.servicio)
);

const precio = (match && match.property_precio != null) ? Number(match.property_precio) : null;

return [{
  json: { ...n, precio },
  pairedItem: { item: 0 }
}];

const d = $json;                 // resultado de Consultar Disponibilidad
const n = $('Normalizar datos entrada').item.json;

const tipo     = String(n.vehiculo || '').toLowerCase();
const esMoto   = tipo === 'moto';
const servicio = String(n.servicio || '').toLowerCase();
const esFullDay = esMoto
  ? servicio.includes('abrillantado de pintura')
  : servicio.includes('completo exterior e interior');

let permitido = true;
let motivo = '';

if (d.dia_bloqueado_full_day) {
  permitido = false;
  motivo = 'ese día ya tiene reservado un trabajo de día completo';
} else if (esFullDay && (d.total_citas || 0) > 0) {
  permitido = false;
  motivo = 'ese servicio ocupa el día completo y ese día ya tiene reservas';
} else if (esMoto && !d.disponibilidad_motos) {
  permitido = false;
  motivo = 'ya no hay cupo para motos ese día';
} else if (!esMoto && !d.disponibilidad_vehiculos) {
  permitido = false;
  motivo = 'ya no hay cupo para vehículos ese día';
}

return [{ json: { permitido, motivo, fecha: n.fecha_recepcion } }];

